using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public required string DocumentText { get; set; }
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
}

using DocSummary.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.AI;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController(IChatClient chatClient, ILogger<SummaryController> logger) : ControllerBase
{
    private const string SystemPrompt =
        "You are a document summarization assistant. " +
        "Given a document, produce a concise summary that captures the key points. " +
        "Return only the summary text with no preamble.";

    [HttpPost]
    public async Task<ActionResult<SummarizeResponse>> Summarize(
        [FromBody] SummarizeRequest request,
        CancellationToken cancellationToken)
    {
        var messages = new List<ChatMessage>
        {
            new(ChatRole.System, SystemPrompt),
            new(ChatRole.User, $"Summarize the following document:\n\n{request.DocumentText}"),
        };

        var options = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 1024,
        };

        var response = await chatClient.GetResponseAsync(messages, options, cancellationToken);
        var summary = response.Text;

        if (string.IsNullOrWhiteSpace(summary))
        {
            logger.LogWarning("LLM returned empty summary");
            return StatusCode(502, "The AI service returned an empty response. Please try again.");
        }

        logger.LogInformation("Summary generated: InputLength={InputLength}, OutputLength={OutputLength}",
            request.DocumentText.Length, summary.Length);

        return Ok(new SummarizeResponse { Summary = summary });
    }
}

